import { useEffect, useRef } from "react";
import suneditor, { plugins } from "suneditor";
import "suneditor/css";
import "suneditor/css/contents";

export default function SunEditorReactExample() {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  useEffect(() => {
    const instance = suneditor.create(textareaRef.current!, {
      plugins,
      value: "<p>Hello SunEditor</p>",
      buttonList: [["undo", "redo"], ["bold", "italic", "underline"], ["link", "image"]]
    });

    return () => instance.destroy();
  }, []);

  return <textarea ref={textareaRef} style={{ visibility: "hidden" }} />;
}

import { AfterViewInit, Component, ElementRef, OnDestroy, ViewChild } from "@angular/core";
import suneditor, { plugins } from "suneditor";
import type { SunEditor } from "suneditor/types";
import "suneditor/css";

@Component({
  selector: "app-editor",
  template: `<textarea #editorEl style="visibility:hidden"></textarea>`
})
export class EditorComponent implements AfterViewInit, OnDestroy {
  @ViewChild("editorEl", { static: true }) editorEl!: ElementRef<HTMLTextAreaElement>;
  private instance: SunEditor.Instance | null = null;

  ngAfterViewInit() {
    this.instance = suneditor.create(this.editorEl.nativeElement, {
      plugins,
      value: "<p>Hello SunEditor</p>",
      buttonList: [["undo", "redo"], ["bold", "italic", "underline"], ["link", "image"]]
    });
  }

  ngOnDestroy() {
    this.instance?.destroy();
  }
}

import suneditor, { plugins } from "suneditor";
import "suneditor/css";

class SunEditorElement extends HTMLElement {
  connectedCallback() {
    this.innerHTML = `<textarea style="visibility:hidden"></textarea>`;

    const textarea = this.querySelector("textarea");
    this.editor = suneditor.create(textarea, {
      plugins,
      value: "<p>Hello SunEditor</p>",
      buttonList: [["undo", "redo"], ["bold", "italic", "underline"], ["link", "image"]]
    });
  }

  disconnectedCallback() {
    this.editor?.destroy();
  }
}

customElements.define("sun-editor", SunEditorElement);
